ode[align=center] (fr) at (0,3.2) {Ward Identities}; \draw[thick,-] (st) -- (as); \draw[thick,-] (st) -- (me); \draw[thick,-] (as) -- (me); \draw[very thick, ->] (fr) -- (me); \draw[very thick, ->] (fr) -- (st); \draw[very thick, ->] (fr) -- (as); \end{tikzpicture} \caption{Three seemingly distinct features of 3d gravity coupled to massless matter -- infinite-dimensional asymptotic symmetry, memory effects, and a soft theorem -- all follow from the constraints of gravity coupled to matter in the far field. These constraints can be interpreted as sourced Ward identities at infinity. They generate the 3d gravity infrared triangle, which can also be regarded as an infrared trivalent vertex.} \label{fig:3d-triangle}
